/**
 * FontAwesome Icons Fallback
 * Lightweight icon system for need2talk
 */

// Simple icon system for need2talk
window.FontAwesome = {
    
    /**
     * Initialize icon system
     */
    init() {
        console.log('[Need2Talk] FontAwesome fallback initialized');
        this.replaceIcons();
    },

    /**
     * Replace FontAwesome icons with Unicode/SVG alternatives
     */
    replaceIcons() {
        const iconMap = {
            'fa-play': '▶️',
            'fa-pause': '⏸️',
            'fa-heart': '❤️',
            'fa-share': '🔗',
            'fa-volume-up': '🔊',
            'fa-volume-mute': '🔇',
            'fa-clock': '⏰',
            'fa-headphones': '🎧',
            'fa-home': '🏠',
            'fa-info-circle': 'ℹ️',
            'fa-lock': '🔒',
            'fa-user': '👤',
            'fa-plus': '➕',
            'fa-times': '❌',
            'fa-check': '✅',
            'fa-exclamation-triangle': '⚠️'
        };

        // Replace FontAwesome classes with Unicode
        Object.keys(iconMap).forEach(faClass => {
            const elements = document.querySelectorAll(`.${faClass}`);
            elements.forEach(element => {
                if (element.tagName === 'I' || element.classList.contains('fas') || element.classList.contains('far')) {
                    element.innerHTML = iconMap[faClass];
                    element.style.fontFamily = 'inherit';
                    element.classList.add('icon-replacement');
                }
            });
        });
    },

    /**
     * Create SVG icon
     */
    createSVGIcon(iconName, size = 16) {
        const svgIcons = {
            play: `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="currentColor">
                     <path d="M8 5v14l11-7z"/>
                   </svg>`,
            pause: `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="currentColor">
                      <path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/>
                    </svg>`,
            heart: `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                      <path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
                    </svg>`,
            share: `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                      <path d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.367 2.684 3 3 0 00-5.367-2.684z"/>
                    </svg>`,
            volume: `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                       <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 13 19 13 5 11 5"/>
                       <path d="M15.54 8.46a5 5 0 010 7.07"/>
                     </svg>`,
            mute: `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                     <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 13 19 13 5 11 5"/>
                     <line x1="23" y1="9" x2="17" y2="15"/>
                     <line x1="17" y1="9" x2="23" y2="15"/>
                   </svg>`
        };

        return svgIcons[iconName] || '';
    },

    /**
     * Replace icon with SVG
     */
    replaceSVGIcon(element, iconName, size = 16) {
        const svg = this.createSVGIcon(iconName, size);
        if (svg) {
            element.innerHTML = svg;
            element.classList.add('svg-icon');
        }
    }
};

// Auto-initialize
document.addEventListener('DOMContentLoaded', function() {
    FontAwesome.init();
    
    // Re-run on dynamic content changes
    const observer = new MutationObserver(function(mutations) {
        let shouldReplace = false;
        
        mutations.forEach(function(mutation) {
            mutation.addedNodes.forEach(function(node) {
                if (node.nodeType === 1 && (node.querySelector?.('.fas, .far, .fab') || node.classList?.contains('fas') || node.classList?.contains('far') || node.classList?.contains('fab'))) {
                    shouldReplace = true;
                }
            });
        });
        
        if (shouldReplace) {
            FontAwesome.replaceIcons();
        }
    });
    
    observer.observe(document.body, {
        childList: true,
        subtree: true
    });
});

// Export for modules if needed
if (typeof module !== 'undefined' && module.exports) {
    module.exports = FontAwesome;
}